import React, { useState } from "react";
import "./App.css";
import weddingPhoto from "./wedding-photo.jpg"; // Votre photo en noir et blanc

function App() {
  const [isOpen, setIsOpen] = useState(false);

  return (
    <div className="app-container">
      {/* ÉTAPE 1 : La lettre d'accueil */}
      {!isOpen ? (
        <div className="page-1-letter" onClick={() => setIsOpen(true)}>
          <div className="letter-content">
            <h1 className="names-title">Elyes & Sarra</h1>
            <h2 className="subtitle">We are getting married</h2>
            <button
              className="open-button"
              onClick={(e) => {
                e.stopPropagation();
                setIsOpen(true);
              }}
            >
              Click to open
            </button>
          </div>
        </div>
      ) : (
        <div
          className="page-2-details"
          style={{ backgroundImage: `url(${weddingPhoto})` }}
        >
          <div className="overlay">
            <div className="content-wrapper fade-in">
              <p className="location-text">
                Hacienda Event - Bourj Touil | 16h
              </p>

              <div className="elegant-frame">
                <h3 className="save-date">Save Our Day</h3>
                <p className="date">22 Mars 2026</p>
              </div>

              <h1 className="initials">E & S</h1>
              <p className="quote">
                Here's to love, joy and the beginning of our forever!
              </p>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
